"""CTE assembler — Phase 5.

Converts an ordered list of CTEFragments into a complete, valid T-SQL script.

Output format
-------------
    -- Generated by alteryx-to-sql-agent
    -- Source: <workflow_name>
    -- Generated: <timestamp>

    WITH
    [cte_name_1] AS (
        <sql body>
    ),
    [cte_name_2] AS (
        <sql body>
    ),
    ...
    [last_cte] AS (
        <sql body>
    )
    SELECT * FROM [last_cte];

The trailing SELECT * FROM [last_cte] makes the script immediately executable
in SSMS / Azure Data Studio.  Users can remove or replace it as needed.

Stub detection
--------------
Any fragment with `is_stub=True` causes the assembler to prepend a block-level
comment so the reviewer can identify incomplete sections quickly.
"""

from __future__ import annotations

from datetime import datetime, timezone

from parsing.models import CTEFragment

_HEADER_TEMPLATE = """\
-- =============================================================================
-- Generated by alteryx-to-sql-agent
-- Source:    {workflow_name}
-- Generated: {timestamp}
-- Stubs:     {stub_count} CTE(s) require manual review
-- =============================================================================
"""

_SECTION_BANNERS: dict[str, str] = {
    "source": (
        "-- -----------------------------------------------------------------------------\n"
        "-- SOURCE LOADING\n"
        "-- -----------------------------------------------------------------------------"
    ),
    "transform": (
        "-- -----------------------------------------------------------------------------\n"
        "-- TRANSFORMATIONS\n"
        "-- -----------------------------------------------------------------------------"
    ),
    "output": (
        "-- -----------------------------------------------------------------------------\n"
        "-- OUTPUT\n"
        "-- -----------------------------------------------------------------------------"
    ),
}


def _classify_fragment(frag: CTEFragment, source_ids: set[int], sink_ids: set[int]) -> str:
    if source_ids and any(tid in source_ids for tid in frag.source_tool_ids):
        return "source"
    if sink_ids and any(tid in sink_ids for tid in frag.source_tool_ids):
        return "output"
    return "transform"


def build_sql(
    fragments: list[CTEFragment],
    workflow_name: str = "unknown",
    source_ids: set[int] | None = None,
    sink_ids: set[int] | None = None,
) -> str:
    """Assemble CTEFragments into a complete T-SQL script.

    Args:
        fragments:      Ordered list of CTEFragments (from translate_chunk calls).
        workflow_name:  The source .yxmd filename (for the header comment).

    Returns:
        A complete, formatted T-SQL string.
    """
    if not fragments:
        return "-- No CTEs generated\nSELECT 1 AS _empty;"

    stub_count = sum(1 for f in fragments if f.is_stub)
    timestamp = datetime.now(timezone.utc).strftime("%Y-%m-%d %H:%M:%S UTC")

    header = _HEADER_TEMPLATE.format(
        workflow_name=workflow_name,
        timestamp=timestamp,
        stub_count=stub_count,
    )

    _source_ids: set[int] = source_ids or set()
    _sink_ids: set[int] = sink_ids or set()
    use_sections = bool(_source_ids or _sink_ids)

    parts: list[str] = []
    current_section: str | None = None

    for i, frag in enumerate(fragments):
        if use_sections:
            section = _classify_fragment(frag, _source_ids, _sink_ids)
            if section != current_section:
                parts.append(_SECTION_BANNERS[section])
                current_section = section

        body = _indent(frag.sql, "    ")
        if frag.is_stub:
            body = "    -- !!! STUB — requires manual review !!!\n" + body

        is_last = i == len(fragments) - 1
        block = f"[{frag.name}] AS (\n{body}\n)" + ("" if is_last else ",")
        parts.append(block)

    cte_section = "\n\n".join(parts)
    last_name = fragments[-1].name

    return f"{header}\nWITH\n{cte_section}\n\nSELECT * FROM [{last_name}];\n"


def _indent(text: str, prefix: str) -> str:
    """Indent every line of text with prefix."""
    return "\n".join(prefix + line for line in text.splitlines())
